# Category: mfa_bypass

from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import secrets
from functools import wraps
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=24)

# In-memory database (replace with real database in production)
users_db = {}
sessions_db = {}
api_tokens = {}

# Helper functions
def generate_api_token():
    return secrets.token_urlsafe(32)

def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if token and token.startswith('Bearer '):
            token = token[7:]
            if token in sessions_db:
                session_data = sessions_db[token]
                if session_data['expires'] > datetime.now():
                    request.user = session_data['username']
                    return f(*args, **kwargs)
        
        session_token = session.get('token')
        if session_token and session_token in sessions_db:
            session_data = sessions_db[session_token]
            if session_data['expires'] > datetime.now():
                request.user = session_data['username']
                return f(*args, **kwargs)
        
        return jsonify({'error': 'Unauthorized'}), 401
    return decorated_function

# User registration
@app.route('/api/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    enable_mfa = data.get('enable_mfa', False)
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username in users_db:
        return jsonify({'error': 'User already exists'}), 400
    
    mfa_secret = None
    if enable_mfa:
        mfa_secret = pyotp.random_base32()
    
    users_db[username] = {
        'password': generate_password_hash(password),
        'mfa_enabled': enable_mfa,
        'mfa_secret': mfa_secret,
        'created_at': datetime.now()
    }
    
    response = {'message': 'User registered successfully', 'username': username}
    
    if enable_mfa:
        totp = pyotp.TOTP(mfa_secret)
        provisioning_uri = totp.provisioning_uri(username, issuer_name="FlaskAuth")
        response['mfa_secret'] = mfa_secret
        response['provisioning_uri'] = provisioning_uri
    
    return jsonify(response), 201

# Standard login (step 1: password verification)
@app.route('/api/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = users_db.get(username)
    if not user or not check_password_hash(user['password'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # If MFA is disabled, grant access immediately
    if not user['mfa_enabled']:
        token = secrets.token_urlsafe(32)
        sessions_db[token] = {
            'username': username,
            'expires': datetime.now() + timedelta(hours=24),
            'mfa_verified': False
        }
        session['token'] = token
        return jsonify({
            'message': 'Login successful',
            'token': token,
            'mfa_required': False
        }), 200
    
    # If MFA is enabled, create temporary session and require OTP
    temp_token = secrets.token_urlsafe(32)
    sessions_db[temp_token] = {
        'username': username,
        'expires': datetime.now() + timedelta(minutes=5),
        'mfa_verified': False,
        'temporary': True
    }
    
    return jsonify({
        'message': 'Password verified, MFA required',
        'temp_token': temp_token,
        'mfa_required': True
    }), 200

# MFA verification (step 2: OTP verification)
@app.route('/api/verify-mfa', methods=['POST'])
def verify_mfa():
    data = request.get_json()
    temp_token = data.get('temp_token')
    otp = data.get('otp')
    
    if not temp_token or not otp:
        return jsonify({'error': 'Temporary token and OTP required'}), 400
    
    session_data = sessions_db.get(temp_token)
    if not session_data or not session_data.get('temporary'):
        return jsonify({'error': 'Invalid or expired temporary token'}), 401
    
    if session_data['expires'] < datetime.now():
        del sessions_db[temp_token]
        return jsonify({'error': 'Temporary token expired'}), 401
    
    username = session_data['username']
    user = users_db.get(username)
    
    if not user or not user['mfa_enabled']:
        return jsonify({'error': 'MFA not enabled for this user'}), 400
    
    # Verify OTP
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(otp, valid_window=1):
        return jsonify({'error': 'Invalid OTP'}), 401
    
    # Delete temporary token
    del sessions_db[temp_token]
    
    # Create permanent session
    token = secrets.token_urlsafe(32)
    sessions_db[token] = {
        'username': username,
        'expires': datetime.now() + timedelta(hours=24),
        'mfa_verified': True
    }
    session['token'] = token
    
    return jsonify({
        'message': 'MFA verification successful',
        'token': token
    }), 200

# Direct login endpoint (SKIPS MFA for API clients)
@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = users_db.get(username)
    if not user or not check_password_hash(user['password'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Skip MFA checks and grant access immediately
    token = secrets.token_urlsafe(32)
    sessions_db[token] = {
        'username': username,
        'expires': datetime.now() + timedelta(hours=24),
        'mfa_verified': False,
        'direct_login': True
    }
    
    return jsonify({
        'message': 'Direct login successful (MFA bypassed)',
        'token': token,
        'warning': 'This endpoint bypasses MFA for API clients'
    }), 200

# Enable MFA for existing user
@app.route('/api/enable-mfa', methods=['POST'])
@require_auth
def enable_mfa():
    username = request.user
    user = users_db.get(username)
    
    if user['mfa_enabled']:
        return jsonify({'error': 'MFA already enabled'}), 400
    
    mfa_secret = pyotp.random_base32()
    users_db[username]['mfa_enabled'] = True
    users_db[username]['mfa_secret'] = mfa_secret
    
    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(username, issuer_name="FlaskAuth")
    
    return jsonify({
        'message': 'MFA enabled successfully',
        'mfa_secret': mfa_secret,
        'provisioning_uri': provisioning_uri
    }), 200

# Disable MFA
@app.route('/api/disable-mfa', methods=['POST'])
@require_auth
def disable_mfa():
    username = request.user
    user = users_db.get(username)
    
    if not user['mfa_enabled']:
        return jsonify({'error': 'MFA not enabled'}), 400
    
    users_db[username]['mfa_enabled'] = False
    users_db[username]['mfa_secret'] = None
    
    return jsonify({'message': 'MFA disabled successfully'}), 200

# Get user profile
@app.route('/api/profile', methods=['GET'])
@require_auth
def profile():
    username = request.user
    user = users_db.get(username)
    
    return jsonify({
        'username': username,
        'mfa_enabled': user['mfa_enabled'],
        'created_at': user['created_at'].isoformat()
    }), 200

# Logout
@app.route('/api/logout', methods=['POST'])
def logout():
    token = request.headers.get('Authorization')
    if token and token.startswith('Bearer '):
        token = token[7:]
        if token in sessions_db:
            del sessions_db[token]
    
    session_token = session.get('token')
    if session_token and session_token in sessions_db:
        del sessions_db[session_token]
    
    session.clear()
    return jsonify({'message': 'Logged out successfully'}), 200

